import { describe, expect, it } from 'vitest';

import {
  adist,
  admitSameProvenance,
  clusterWithinTwoTol,
  fpDistance,
  mismatchPenalty,
  ProvenanceTransitivityMaster,
  ref,
  ref2,
  w,
  x,
  y,
  z,
} from '../src/provenance-transitivity';

describe('adist (mirrors adist_self / adist_comm)', () => {
  it('is zero at a point with itself', () => {
    for (const a of [0, 1, 5, 42]) {
      expect(adist(a, a)).toBe(0);
    }
  });

  it('is the absolute difference and symmetric', () => {
    expect(adist(21, 20)).toBe(1);
    expect(adist(20, 21)).toBe(1);
    expect(adist(40, 20)).toBe(20);
  });
});

describe('fpDistance (mirrors fpDistance / fpDistance_self)', () => {
  it('is zero from a fingerprint to itself', () => {
    expect(fpDistance(ref, ref)).toBe(0);
    expect(fpDistance(x, x)).toBe(0);
  });

  it('sums pointwise adist on the fixtures', () => {
    expect(fpDistance(x, ref)).toBe(2); // 1 + 1 + 0
    expect(fpDistance(y, ref)).toBe(3); // 1 + 1 + 1
    expect(fpDistance(x, y)).toBe(5); // 2 + 2 + 1
    expect(fpDistance(z, ref)).toBe(60); // 20 + 20 + 20
    expect(fpDistance(x, w)).toBe(60); // 20 + 20 + 20
  });

  it('returns the sentinel on a length mismatch', () => {
    expect(fpDistance([1, 2], [1, 2, 3])).toBe(mismatchPenalty);
  });
});

describe('promotion check: admitSameProvenance', () => {
  it('admits a member that matches the reference within tolerance', () => {
    const a = admitSameProvenance(x, ref, { tol: 4 });
    expect(a.outcome).toBe('claim_admitted');
    expect(a.matched).toBe(true);
    expect(a.distance).toBe(2);

    const b = admitSameProvenance(y, ref, { tol: 4 });
    expect(b.outcome).toBe('claim_admitted');
    expect(b.distance).toBe(3);
  });

  it('withholds a member separated beyond tolerance (distinct reference)', () => {
    const a = admitSameProvenance(z, ref, { tol: 4 });
    expect(a.outcome).toBe('claim_withheld');
    expect(a.limitation).toBe('distinct_reference');
    expect(a.matched).toBe(false);
    expect(a.distance).toBe(60);
  });

  it('reports a self-reference (zero distance) as observation_only, not promoted', () => {
    const a = admitSameProvenance(ref, ref, { tol: 4 });
    expect(a.outcome).toBe('observation_only');
    expect(a.limitation).toBe('self_reference');
    expect(a.distance).toBe(0);
  });

  it('withholds even a hair beyond tolerance', () => {
    // x to ref is distance 2; tol 1 should withhold
    const a = admitSameProvenance(x, ref, { tol: 1 });
    expect(a.outcome).toBe('claim_withheld');
  });
});

describe('transitivity bound: clusterWithinTwoTol', () => {
  it('fires for two members sharing the reference (x, y within 2*tol)', () => {
    const b = clusterWithinTwoTol(x, y, ref, 4);
    expect(b.xMatchesRef).toBe(true);
    expect(b.yMatchesRef).toBe(true);
    expect(b.bothMatch).toBe(true);
    expect(b.pairDistance).toBe(5);
    expect(b.bound).toBe(8);
    expect(b.withinBound).toBe(true);
  });

  it('does not assert when a member does not share the reference', () => {
    // x matches ref, z does not; precondition unmet so no throw, reports facts.
    const b = clusterWithinTwoTol(x, z, ref, 4);
    expect(b.xMatchesRef).toBe(true);
    expect(b.yMatchesRef).toBe(false);
    expect(b.bothMatch).toBe(false);
  });

  it('throws if the transitivity bound is ever violated under a satisfied precondition', () => {
    // Construct a degenerate scenario: with a very loose tolerance both far
    // points "match" the reference, but the pairwise distance exceeds 2*tol.
    // ref=[0], a=[0] (dist 0), b=[100] (dist 100). tol=100 => both match,
    // 2*tol=200, fpDistance(a,b)=100 <= 200 so no violation here.
    // To force a violation we need bothMatch but pair > 2*tol, which the
    // triangle inequality forbids for a true metric — so this should NOT throw.
    expect(() => clusterWithinTwoTol([0], [100], [0], 100)).not.toThrow();
  });
});

describe('ProvenanceTransitivityMaster (mirrors provenance_transitivity_master)', () => {
  it('every boundary witness holds', () => {
    expect(ProvenanceTransitivityMaster.xMatchesRef).toBe(true);
    expect(ProvenanceTransitivityMaster.yMatchesRef).toBe(true);
    expect(ProvenanceTransitivityMaster.zNotMatchRef).toBe(true);
    expect(ProvenanceTransitivityMaster.transitivityBoundHolds).toBe(true);
    expect(ProvenanceTransitivityMaster.clusterBothMatch).toBe(true);
    expect(ProvenanceTransitivityMaster.referencesWellSeparated).toBe(true);
    expect(ProvenanceTransitivityMaster.distinctReferenceNotShared).toBe(true);
  });

  it('the references really are well separated (non-vacuous hard negative)', () => {
    expect(fpDistance(ref2, ref)).toBe(60);
    expect(fpDistance(ref2, ref)).toBeGreaterThan(2 * 4);
  });

  it('distinct references do not share provenance (x vs w beyond 2*tol)', () => {
    expect(fpDistance(x, w)).toBe(60);
    expect(fpDistance(x, w)).toBeGreaterThan(2 * 4);
  });
});
